import GridItem from "./GridItem";

export default function Grid({ items, selected, onSelect }) {
  return (
    <div className="grid">
      {items.map((item) => (
        <GridItem
          key={item.id}
          item={item}
          selected={selected?.id === item.id}
          onClick={() => onSelect(item)}
        />
      ))}
    </div>
  );
}
